+  );
+
+  const config: FooterConfigSnapshot = {
+    ...DEFAULT_FOOTER_CONFIG,
+    defaultIconColor: "muted",
+    defaultTextColor: "warning",
+    widgets: { branch: { iconColor: "muted", textColor: "warning" } },
+  };
+  assert.equal(widgetSummary(config, "branch"), "default");
+});
